# the SQLite locking issue that might arise.

from django.test import TestCase
from django.contrib.auth.models import User
from django.db import connections, DatabaseError
from django.db.utils import OperationalError

class MultiDatabaseTests(TestCase):

    databases = {'default', 'other'}

    @classmethod
    def setUpTestData(cls):
        # Set up initial data for the database. This could potentially lead to
        # a locking issue with SQLite when running with --keepdb.
        try:
            User.objects.using('default').create_superuser(
                username='admin', email='admin@example.com', password='password'
            )
        except OperationalError as e:
            if 'database is locked' in str(e):
                # This is where we would catch the specific case for a locked database
                print("Database is locked during setup: ", str(e))
            else:
                raise

        User.objects.using('other').create_superuser(
            username='admin2', email='admin2@example.com', password='password'
        )

    def test_database_access(self):
        # Test database access across multiple databases to ensure locking does not occur
        try:
            user1 = User.objects.using('default').get(username='admin')
            user2 = User.objects.using('other').get(username='admin2')
            self.assertIsNotNone(user1)
            self.assertIsNotNone(user2)
        except OperationalError as e:
            if 'database is locked' in str(e):
                self.fail(f"Test failed due to locked database: {e}")

    def test_database_lock_handling(self):
        # Check that session closing and management do not hit the lock issue
        for conn_name in self.databases:
            with self.subTest(database=conn_name):
                try:
                    cursor = connections[conn_name].cursor()
                    cursor.execute("SELECT 1")
                except OperationalError as e:
